import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

const gold = '#D4AF37';
const shinyGold = 'linear-gradient(135deg, #fceabb 0%, #fccd4d 50%, #f8b500 51%, #fbdf93 100%)';

// --- COMPACT WIG STORE ---
const WigStore = () => {
  const categories = [
    {
      type: "Human Hair",
      items: [{ name: "Luxury Raw Cambodian", price: "85,000", desc: "14-inch frontal unit." }]
    },
    {
      type: "Premium Fibre",
      items: [{ name: "Sleek Straight Unit", price: "35,000", desc: "Heat resistant & pre-styled." }]
    },
    {
      type: "Hair Blend",
      items: [{ name: "Piano Wavy T-Closure", price: "25,000", desc: "24-inch high volume blend." }]
    }
  ];

  return (
    <div style={{ padding: '0 15px' }}>
      {categories.map((cat) => (
        <div key={cat.type} style={{ marginBottom: '25px' }}>
          <h3 style={{ fontSize: '0.75rem', color: gold, textTransform: 'uppercase', letterSpacing: '2px', marginBottom: '12px', borderBottom: '1px solid #222', paddingBottom: '5px' }}>
            {cat.type}
          </h3>
          {cat.items.map((item) => (
            <div key={item.name} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '12px', marginBottom: '10px', padding: '12px', alignItems: 'center' }}>
              <div style={{ width: '60px', height: '60px', backgroundColor: '#000', borderRadius: '8px', marginRight: '12px' }}></div>
              <div style={{ flex: 1 }}>
                <h4 style={{ fontSize: '0.85rem', margin: '0', color: '#fff' }}>{item.name}</h4>
                <div style={{ fontSize: '0.9rem', fontWeight: 'bold', color: gold }}>₦{item.price}</div>
              </div>
              <button style={{ backgroundColor: gold, color: '#000', border: 'none', borderRadius: '20px', padding: '5px 12px', fontSize: '0.65rem', fontWeight: 'bold' }}>ADD</button>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
};

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);

  // HOW TO ADD IMAGES: 
  // 1. Put your images in the 'public' folder.
  // 2. Change the 'img' paths below to match your filenames (e.g., 'chops.jpg')
  const slides = [
    { title: "THE SMALL CHOPS", subtitle: "Every bite, always worth it.", img: "https://via.placeholder.com/800x400/D4AF37/000000?text=Small+Chops+Photo" },
    { title: "THE HAIR EDIT", subtitle: "Premium Human Hair & Blends.", img: "https://via.placeholder.com/800x400/D4AF37/000000?text=Wig+Photo" },
    { title: "OFFICE LUNCH", subtitle: "Corporate Dining, Delivered.", img: "https://via.placeholder.com/800x400/D4AF37/000000?text=Lunch+Photo" }
  ];

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((s) => (s + 1) % slides.length);
    }, 4000);
    return () => clearInterval(timer);
  }, [slides.length]);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. STICKY HEADER */}
      <header style={{ padding: '12px 20px', borderBottom: '1px solid #111', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: '#000', zIndex: 100 }}>
        <img src={Logo} alt="Logo" style={{ height: '30px' }} />
        <div style={{ display: 'flex', gap: '15px', fontSize: '1.2rem' }}>👤 🛒</div>
      </header>

      {/* 2. SHINY GOLD ANIMATED HERO */}
      <div style={{ width: '100%', height: '200px', position: 'relative', overflow: 'hidden', background: shinyGold }}>
        {slides.map((slide, index) => (
          <div key={index} style={{
            position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
            opacity: index === currentSlide ? 1 : 0,
            transition: 'opacity 1s ease-in-out',
            display: 'flex', alignItems: 'center', justifyContent: 'center'
          }}>
            {/* THIS IS WHERE YOUR IMAGE SHOWS UP */}
            <img src={slide.img} alt={slide.title} style={{ position: 'absolute', width: '100%', height: '100%', objectFit: 'cover', opacity: 0.6 }} />
            
            <div style={{ position: 'relative', zIndex: 2, textAlign: 'center', padding: '20px' }}>
              <h2 style={{ fontSize: '1.5rem', color: '#000', fontWeight: '900', margin: '0 0 5px 0', textTransform: 'uppercase' }}>{slide.title}</h2>
              <p style={{ fontSize: '0.8rem', color: '#333', fontWeight: '600', margin: 0 }}>{slide.subtitle}</p>
            </div>
          </div>
        ))}
      </div>

      {/* 3. INFO BLOCK */}
      <div style={{ padding: '20px' }}>
        <h1 style={{ fontSize: '1.1rem', margin: '0' }}>Àmí by T - Lagos</h1>
        <p style={{ fontSize: '0.7rem', color: '#888', margin: '5px 0 15px' }}>● Opened · Closes 08:00 PM</p>
        <div style={{ display: 'flex', gap: '10px' }}>
          <button style={{ flex: 1, padding: '10px', borderRadius: '20px', border: 'none', backgroundColor: '#fff', color: '#000', fontWeight: 'bold', fontSize: '0.8rem' }}>Pickup</button>
          <button style={{ flex: 1, padding: '10px', borderRadius: '20px', border: '1px solid #333', backgroundColor: 'transparent', color: '#fff', fontSize: '0.8rem' }}>Delivery</button>
        </div>
      </div>

      {/* 4. HORIZONTAL NAVIGATION */}
      <div style={{ display: 'flex', gap: '8px', overflowX: 'auto', padding: '0 20px 20px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs', 'About'].map((item) => (
          <button 
            key={item} 
            onClick={() => setActiveCategory(item)}
            style={{ 
              whiteSpace: 'nowrap', padding: '8px 18px', borderRadius: '20px', border: 'none',
              backgroundColor: activeCategory === item ? gold : '#1A1A1A',
              color: activeCategory === item ? '#000' : '#fff',
              fontSize: '0.75rem', fontWeight: '700'
            }}
          >
            {item}
          </button>
        ))}
      </div>

      {/* 5. CONTENT AREA */}
      <main style={{ paddingBottom: '80px' }}>
        <h3 style={{ padding: '0 20px 15px', fontSize: '1rem', borderLeft: `3px solid ${gold}`, marginLeft: '20px' }}>{activeCategory}</h3>
        {activeCategory === 'Wigs' && <WigStore />}
        {activeCategory === 'Small Chops' && <Menu />}
        {activeCategory === 'Office Lunch' && <Lunch />}
      </main>

    </div>
  );
}

export default App;
